import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { orders } from '../api';
import { useApp } from '../context/AppContext';

const Checkout = () => {
  const [form, setForm] = useState({ customer_name: '', customer_phone: '', customer_address: '' });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const { cart, cartTotal, clearCart } = useApp();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    try {
      await orders.create({
        ...form,
        items: cart.map(item => ({ id: item.id, quantity: item.quantity, price: item.price }))
      });
      clearCart();
      setMessage('✅ Buyurtma muvaffaqiyatli qabul qilindi!');
      setTimeout(() => navigate('/orders'), 2000);
    } catch (err) {
      setMessage('❌ Xatolik yuz berdi. Qaytadan urinib ko\'ring.');
    } finally {
      setLoading(false);
    }
  };

  if (cart.length === 0) {
    return (
      <div className="container checkout-page">
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="empty"
        >
          Savat bo'sh
        </motion.div>
      </div>
    );
  }

  return (
    <div className="container checkout-page">
      <motion.h1 
        className="section-title"
        initial={{ y: -20, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
      >
        Buyurtma
      </motion.h1>

      {message && (
        <motion.div 
          className={`message ${message.includes('muvaffaqiyatli') ? 'success' : 'error'}`}
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
        >
          {message}
        </motion.div>
      )}

      <motion.form 
        className="form"
        onSubmit={handleSubmit}
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.1 }}
      >
        <div className="form-group">
          <label>Ism</label>
          <input 
            type="text" 
            value={form.customer_name} 
            onChange={e => setForm({...form, customer_name: e.target.value})} 
            required 
          />
        </div>
        <div className="form-group">
          <label>Telefon</label>
          <input 
            type="tel" 
            value={form.customer_phone} 
            onChange={e => setForm({...form, customer_phone: e.target.value})} 
            required 
          />
        </div>
        <div className="form-group">
          <label>Manzil</label>
          <input 
            type="text" 
            value={form.customer_address} 
            onChange={e => setForm({...form, customer_address: e.target.value})} 
          />
        </div>

        <div className="cart-total">
          Jami: <strong>{cartTotal.toLocaleString()} so'm</strong>
        </div>

        <motion.button 
          type="submit" 
          className="btn"
          disabled={loading}
          whileTap={{ scale: 0.98 }}
          style={{ width: '100%' }}
        >
          {loading ? 'Yuborilmoqda...' : 'Buyurtma berish'}
        </motion.button>
      </motion.form>
    </div>
  );
};

export default Checkout;
